import {
  DateRangePicker,
  DateRangePickerContent,
  DateRangePickerTrigger,
  SegmentedControl,
  SegmentedControlItem,
} from "@optiaxiom/react";
import { useState } from "react";

import { presetToRange } from "./presetToRange";

export function App() {
  const [preset, setPreset] = useState("custom");
  const [value, setValue] = useState<null | { from: Date; to: Date }>(null);

  return (
    <DateRangePicker
      onValueChange={(value) => {
        setPreset("custom");
        setValue(value);
      }}
      value={value}
    >
      <DateRangePickerTrigger w="224" />
      <DateRangePickerContent
        addonBefore={
          <SegmentedControl
            flexDirection="column"
            gap="2"
            mr="8"
            onValueChange={(preset: string) => {
              if (!preset || preset === "custom") {
                return;
              }

              setPreset(preset);
              setValue(presetToRange(preset));
            }}
            value={preset}
          >
            <SegmentedControlItem value="today">Today</SegmentedControlItem>
            <SegmentedControlItem value="week">This week</SegmentedControlItem>
            <SegmentedControlItem value="month">
              This month
            </SegmentedControlItem>
            <SegmentedControlItem value="next-week">
              Next week
            </SegmentedControlItem>
            <SegmentedControlItem value="next-month">
              Next month
            </SegmentedControlItem>
            <SegmentedControlItem value="custom">Custom</SegmentedControlItem>
          </SegmentedControl>
        }
      />
    </DateRangePicker>
  );
}

export const presetToRange = (preset: string) => {
  const today = new Date();
  switch (preset) {
    case "month":
      return { from: startOfMonth(today), to: endOfMonth(today) };
    case "next-month": {
      const nextMonth = new Date(today);
      nextMonth.setDate(1);
      nextMonth.setMonth(nextMonth.getMonth() + 1);
      return { from: startOfMonth(nextMonth), to: endOfMonth(nextMonth) };
    }
    case "next-week": {
      const nextWeek = new Date(today);
      nextWeek.setDate(nextWeek.getDate() + 7);
      return { from: startOfWeek(nextWeek), to: endOfWeek(nextWeek) };
    }
    case "today":
      return { from: today, to: today };
    case "week":
      return { from: startOfWeek(today), to: endOfWeek(today) };
  }
  return null;
};

const endOfMonth = (date: Date) => {
  const result = startOfMonth(date);
  result.setMonth(result.getMonth() + 1);
  result.setDate(0);
  return result;
};

const startOfMonth = (date: Date) => {
  const result = new Date(date);
  result.setDate(1);
  return result;
};

const endOfWeek = (date: Date) => {
  const result = startOfWeek(date);
  result.setDate(result.getDate() + 6);
  return result;
};

const startOfWeek = (date: Date) => {
  const result = new Date(date);
  result.setDate(result.getDate() - result.getDay());
  return result;
};

