import { Menu, MenuContent, MenuTrigger } from "@optiaxiom/react";

import { useQuery } from "./useQuery";

const colors = [
  {
    label: "Ocean",
    visible: true,
  },
  {
    label: "Blue",
    visible: true,
  },
  {
    label: "Purple",
    visible: true,
  },
  {
    label: "Red",
    visible: true,
  },
  {
    label: "Orange",
    visible: true,
  },
  {
    label: "Yellow",
    visible: true,
  },
];

export function App() {
  const {
    data = [],
    isLoading,
    refetch,
  } = useQuery((inputValue: string) =>
    inputValue
      ? colors.filter((color) =>
          color.label.toLowerCase().startsWith(inputValue.toLowerCase()),
        )
      : colors,
  );

  return (
    <Menu
      inputVisible="always"
      loading={isLoading && "spinner"}
      onInputValueChange={(inputValue) => refetch(inputValue)}
      options={data}
    >
      <MenuTrigger w="224">Select colors</MenuTrigger>
      <MenuContent />
    </Menu>
  );
}

import { useCallback, useEffect, useRef, useState } from "react";

export const useQuery = <
  T extends (...args: [inputValue: string]) => ReturnType<T>,
>(
  fetchFn: T,
) => {
  const [data, setData] = useState<ReturnType<T>>();
  const [isLoading, setIsLoading] = useState(true);

  const fetchRef = useRef(fetchFn);
  fetchRef.current = fetchFn;

  const timerRef = useRef<number>();

  const refetch = useCallback((...args: [inputValue: string]) => {
    setIsLoading(true);
    window.clearTimeout(timerRef.current);
    timerRef.current = window.setTimeout(() => {
      setData(fetchRef.current(...args));
      setIsLoading(false);
    }, 600);
  }, []);

  useEffect(() => {
    refetch("");
  }, [refetch]);

  return { data, isLoading, refetch };
};

