import { Sortable, SortableItem } from "@optiaxiom/react/unstable";
import { useState } from "react";

import { calculateRank } from "./calculateRank";

export function App() {
  const [data, setData] = useState([
    {
      id: "A",
      rank: 10_000,
    },
    {
      id: "B",
      rank: 20_000,
    },
    {
      id: "C",
      rank: 30_000,
    },
  ]);

  return (
    <Sortable
      items={data.toSorted((a, b) => a.rank - b.rank).map((item) => item.id)}
      onChange={({ items, source }) => {
        setData(
          data.map((item) =>
            item.id === source
              ? {
                  ...item,
                  rank: calculateRank(data, source, items),
                }
              : item,
          ),
        );
      }}
    >
      {(items) =>
        items.map((item, index) => (
          <SortableItem border="1" index={index} item={item} key={item}>
            Item {item}
          </SortableItem>
        ))
      }
    </Sortable>
  );
}

export function calculateRank(
  data: Array<{ id: string; rank: number }>,
  source: string,
  items: string[],
) {
  const findItemRank = (id: string | undefined, fallbackRank: number) => {
    if (!id) {
      return fallbackRank;
    }

    return data.find((item) => item.id === id)?.rank ?? fallbackRank;
  };

  const newIndex = items.indexOf(source);

  const prevItemRank = findItemRank(items[newIndex - 1], 0);
  const nextItemRank = findItemRank(items[newIndex + 1], 40_000);

  return (prevItemRank + nextItemRank) / 2;
}

