      onItemsChange={setItems}
    >
      {(items) =>
        Object.entries(items).map(([column, items], index) => (
          <SortableGroup
            asChild
            gap="0"
            group={column}
            index={index}
            key={column}
            overflow="hidden"
            rounded="sm"
          >
            {(isDropTarget) => (
              <Box
                bg={isDropTarget ? "bg.warning.subtle" : "bg.secondary"}
                transition="colors"
              >
                <Box
                  bg={isDropTarget ? "bg.warning.light" : "bg.avatar.neutral"}
                  p="12"
                  transition="colors"
                >
                  {column}
                </Box>
                <Group
                  flex="1"
                  flexDirection="column"
                  gap="16"
                  justifyContent="flex-start"
                  p="12"
                >
                  {items.map((item, index) => (
                    <SortableItem
                      bg="bg.default"
                      index={index}
                      item={item}
                      key={item}
                      p="24"
                      rounded="sm"
                      textAlign="center"
                      w="224"
                    >
                      Item {item}
                    </SortableItem>
                  ))}
                </Group>
              </Box>
            )}
          </SortableGroup>
        ))
      }
    </Sortable>
  );
}

