Box.source:
import { describe, expect, it } from "vitest";

import { render, screen } from "../../vitest.rtl";
import { Button } from "../button";
import { Text } from "../text";
import { Box } from "./Box";

describe("Box component", () => {
  it("should render properly", () => {
    render(<Box>This is a box</Box>);
    expect(screen.getByText(/This is a box/i)).toBeInTheDocument();
  });

  it("should merge sprinkle props properly for direct props", () => {
    render(
      <Box asChild mx="4">
        <Box asChild mx="2">
          <Box mx="0">This is a box</Box>
        </Box>
      </Box>,
    );
    expect(screen.getByText(/This is a box/i)).not.toContainHTML(
      "marginLeft_4",
    );
    expect(screen.getByText(/This is a box/i)).not.toContainHTML(
      "marginLeft_2",
    );
    expect(screen.getByText(/This is a box/i)).toContainHTML("marginLeft_0");
  });

  it("should merge sprinkle props properly for direct undefined props", () => {
    render(
      <Box asChild mx="4">
        <Box asChild mx="2">
          <Box mx={undefined}>This is a box</Box>
        </Box>
      </Box>,
    );
    expect(screen.getByText(/This is a box/i)).not.toContainHTML(
      "marginLeft_4",
    );
    expect(screen.getByText(/This is a box/i)).toContainHTML("marginLeft_2");
  });

  it("should merge sprinkle props properly for direct shorthand props", () => {
    render(
      <Box asChild mx="4">
        <Box m="2">This is a box</Box>
      </Box>,
    );
    expect(screen.getByText(/This is a box/i)).not.toContainHTML(
      "marginLeft_4",
    );
    expect(screen.getByText(/This is a box/i)).toContainHTML("marginLeft_2");
  });

  it("should merge sprinkle props properly for shorthand and longhand props", () => {
    render(
      <Box m="4" ml="2">
        This is a box
      </Box>,
    );
    expect(screen.getByText(/This is a box/i)).not.toContainHTML(
      "marginLeft_4",
    );
    expect(screen.getByText(/This is a box/i)).toContainHTML("marginLeft_2");
  });

  it("should merge sprinkle props properly for responsive props", () => {
    render(<Box flexDirection={["column", "row"]}>This is a button</Box>);
    expect(screen.getByText("This is a button")).toContainHTML(
      "flexDirection_column",
    );
    expect(screen.getByText("This is a button")).toContainHTML(
      "flexDirection_row",
    );
  });

  it("should merge sprinkle props properly for indirect props", () => {
    render(
      <Text asChild fontSize="sm">
        <Button>This is a button</Button>
      </Text>,
    );
    expect(screen.getByRole("button")).not.toContainHTML("fontSize_sm");
    expect(screen.getByRole("button")).toContainHTML("fontSize_md");
  });
});

Button.source:
import { describe, expect, it, vi } from "vitest";

import { render, screen } from "../../vitest.rtl";
import { Button } from "./Button";

describe("Button component", () => {
  function setup(overrides = {}) {
    const props = {
      children: "Click Me",
      ...overrides,
    };
    return render(<Button {...props} />);
  }

  it("should render button", async () => {
    setup();
    expect(
      screen.getByRole("button", { name: "Click Me" }),
    ).toBeInTheDocument();
  });

  it("should call onClick handler when clicked", async () => {
    const handleClick = vi.fn();
    const { user } = setup({ onClick: handleClick });
    const buttonElement = screen.getByRole("button", { name: "Click Me" });
    await user.click(buttonElement);
    expect(handleClick).toHaveBeenCalledTimes(1);
  });

  it("should not call onClick handler when disabled", async () => {
    const handleClick = vi.fn();
    const { user } = setup({ disabled: true, onClick: handleClick });
    const buttonElement = screen.getByRole("button", { name: "Click Me" });
    await user.click(buttonElement);
    expect(handleClick).not.toHaveBeenCalled();
  });

  it("should apply correct aria attributes for accessibility", async () => {
    const ariaLabel = "Custom Label";
    setup({ "aria-label": ariaLabel });
    const buttonElement = screen.getByLabelText(ariaLabel);
    expect(buttonElement).toBeInTheDocument();
  });

  it("should render different children text", async () => {
    const customText = "Submit";
    setup({ children: customText });
    expect(
      screen.getByRole("button", { name: customText }),
    ).toBeInTheDocument();
  });

  it("should be disabled if loading=true", async () => {
    const handleClick = vi.fn();
    const { user } = setup({ loading: true });

    await user.click(screen.getByRole("button"));

    expect(handleClick).not.toHaveBeenCalled();
  });

  it("should support aria-label", async () => {
    setup({ "aria-label": "Aria Label", children: null });

    expect(screen.getByRole("button", { name: "Aria Label" })).toBeVisible();
  });
});

